features.snippet:
module child(input clock, input [7:0] a);
  TestPropery: cover property (@(posedge clock) a == 8'h0);
endmodule

module top(input clock, input [7:0] a, input [7:0] b);
  wire c1_clock, c2_clock;
  wire [7:0] c1_a, c2_a;
  child c1 (.clock(c1_clock), .a(c1_a));
  child c2 (.clock(c2_clock), .a(c2_a));
  assign c1_clock = clock;
  assign c1_a = a;
  assign c2_clock = clock;
  assign c2_a = b;
endmodule
